package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreEmptyLines() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertTrue(original.getIgnoreEmptyLines(), "DEFAULT format should ignore empty lines");

        CSVFormat result = original.withIgnoreEmptyLines();
        assertNotNull(result);
        assertTrue(result.getIgnoreEmptyLines(), "Resulting format should ignore empty lines");

        // The returned instance should be the same if already true
        assertSame(original, result, "withIgnoreEmptyLines() should return same instance if ignoreEmptyLines is true");
    }
}
